var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……그런 일이 있었군요.","JPN":"……そんなことがあったんですね。","ENG":"...So, that's what happened.","TWN":"……原來是這樣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"병문안이 늦어져서 미안하네. 변명이라고 하기엔 구차하네만.","JPN":"お見舞いが遅くなって悪いかったね。言い訳にしてはお粗末だったが。","ENG":"I'm sorry for taking this long to visit. I have no excuse for it.","TWN":"抱歉，這麼晚才來看你，這個解釋很站不住腳吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 쉽게 납득해 줘서 놀랐다네.","JPN":"あまりにもすんなり納得してくれて驚いたよ。","ENG":"But I am surprised you understood it so easily.","TWN":"沒想到你這麼容易就接受。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모시는 주인님의 성품을 알아보는 것도 메이드가 갖춰야 할 덕목이죠.","JPN":"お仕えするご主人様の人となりを見抜くことも、メイドが備えるべき徳目ですので。","ENG":"It is a maid's virtue to be adept of know her master's character.","TWN":"明白主人的品格也是女僕應該具備的特質。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이렇게 몸소 와 주셔서 영광입니다.","JPN":"こうやって直接お越しいただくなんて、恐縮です。","ENG":"I am honored that you came to visit me.","TWN":"主人親自造訪，是我的榮幸。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 관리국의 개입은 다소 우려스럽군요.","JPN":"ですが、管理局の介入は少々心配ですね。","ENG":"But the intervention of the Administration is somewhat concerning.","TWN":"不過管理局的介入令人有點擔心呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"절묘한 시기를 노렸다는 인상을 지우기 어렵습니다.","JPN":"絶妙な時期を狙っていたという印象を拭いきれません。","ENG":"I can't shake the feeling that they were deliberately waiting for the right moment.","TWN":"畢竟很難消除他們虎視眈眈的印象。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……동감일세. 그건 차차 알아나가야지.","JPN":"……同感だ。それはこれから調べないとな。","ENG":"...I couldn't agree with you more. But we will find out soon enough.","TWN":"……我同意，必須慢慢釐清。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당분간 내 걱정은 말고 자네 몸조리에 신경 쓰게나.","JPN":"しばらくは私の心配はせず、自分の身体を労わりたまえ。","ENG":"For the time being, don't worry about me and take care of yourself.","TWN":"這段時間你就別擔心我，好好保重身體。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모네 양의 고향으로 요양을 간다고 했던가?","JPN":"モネ君の故郷まで療養に行くと言ったかな？","ENG":"I understand you're going to Mone's hometown to rest, is that right?","TWN":"我聽說你要去莫妮的家鄉修養嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 모네 양 어머님께서도 흔쾌히 허락해 주셔서, 퇴원하는 대로 신세를 질 듯합니다.","JPN":"はい。モネさんのお母様も快諾してくださいましたので、退院でき次第お世話になることになりそうです。","ENG":"Yes. Mone's mother happily obliged, so I will be staying there once I get discharged from here.","TWN":"是的，莫妮的媽媽也很爽快地答應，等我出院後就會去他們家打擾。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래도 제가 필요하실 때는, 언제든 불러 주시길.","JPN":"でも必要があれば、いつでもお呼びください。","ENG":"However, please call me when you need my help.","TWN":"不過主人有需要我時，請隨時找我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 말 말게. 당장 자네에게 진 빚을 갚기도 빠듯해.","JPN":"そんなこと言わないでくれ。君への恩を返すのも精一杯さ。","ENG":"Don't say that. It is hard enough to repay you as it is now.","TWN":"別這麼說，我之前欠你的人情債都還沒還清呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그럼 가 보겠네. 편히 쉬게나. 베로니카 양.","JPN":"……それでは、これで失礼する。ゆっくり休みたまえ。ベロニカ君。","ENG":"...Then, I better get going. Rest well, Veronica.","TWN":"……那我先走一步，你好好休息，貝洛妮卡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 주인님.","JPN":"はい。ご主人様。","ENG":"Yes, Master.","TWN":"好的，主人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모쪼록 주인님의 앞날에 행운이 기다리고 있기를 기원하겠습니다.","JPN":"どうか、ご主人様の未来に幸運がありますことを。","ENG":"I wish you the best of luck in the future, Master.","TWN":"希望主人之後一切都順利。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"조력자들까지 들쑤시러 온 건가?","JPN":"協力者たちにまで手を回しに来たのか？","ENG":"Are you here to interrogate my cooperator?","TWN":"連我的幫手你也不放過嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"음? 르네 양, 여긴 무슨 일인가?","JPN":"む？　ルネ君、ここには何の用かね？","ENG":"Hmm? Renée, what brings you here?","TWN":"嗯？芮妮，你來這裡有什麼事嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"안심하시지. 그런 비겁한 짓은 내 취향이 아니야.","JPN":"安心しろ。そんな卑怯なマネは私の趣味ではない。","ENG":"Paranoid much? Going behind people's backs isn't my style.","TWN":"放心吧，我才不是那麼卑鄙的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……아무래도 마음에 걸려서 말이지.","JPN":"……どうしても気にかかってな。","ENG":"...It's just that I can't get my mind off something.","TWN":"……因為我一直在想，"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"왜 순순히 우리 결정에 따랐지?","JPN":"どうして素直に我々の決定に従った？","ENG":"Why did you decide to obey us so easily?","TWN":"為什麼你會乖乖聽從我們的決定？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"알파트릭스 그룹도, 저 괴물 같은 전직 암살자도, 프리드웬도, 구 관리국의 전력도….","JPN":"アルファトリックスグループも、あの化け物のような元暗殺者も、プリドウェンも、旧管理局の戦力も……","ENG":"Alphatrix Group, that former assassin of a monster, Prydwen, or even the forces of the Old Administration...","TWN":"阿爾法崔克斯集團，那個像怪物般的前任殺手，普利多溫，還有管理局的戰力…"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신이 끌어들인다고 해서 딱히 발을 뺄 것 같지는 않았는데.","JPN":"あなたが引き込んだとしても、別段彼らがこの件から身を引くようには思えないのに。","ENG":"It didn't seem like they were going to play dumb just because you got involved.","TWN":"只要你出面，他們應該都不會拒絕。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"자네 같은 미인의 부탁을 거절할 수 있어야지.","JPN":"君のような美人の頼みを断るわけにはいかないだろう。","ENG":"How could I refuse a request from a gorgeous woman like yourself?","TWN":"我怎麼能拒絕像你這種美女的要求呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국을 맡겼으니 결정도 존중해 줘야지.","JPN":"管理局を任せた以上、その決定も尊重すべきだろう。","ENG":"I left the Administration to you. I respect your decision.","TWN":"既然我已經管理局交給你們，就該尊重你們的決定。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"미인……?","JPN":"美人……？","ENG":"Gorgeous...?","TWN":"美女……？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그, 그딴 농담 두 번 다시 하지 마! 확 수플렉스로 처박아 버린다!","JPN":"に、二度とそんな冗談を言うな！　スープレックスをお見舞いするぞ！","ENG":"D-don't you ever pull a joke like that on me again! Or I'm gonna suplex you to the ground!","TWN":"你，不准再開這種玩笑！否則當心我把你過肩摔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"쳇. 역시 무리군. 내가 잭슨도 아닌데 요괴 같은 댁 속내를 어떻게 떠 보겠어.","JPN":"チッ。やはり無理だな。ジャクソンでもあるまいし、妖怪みたいなあなたの心の内なんか知るすべもない。","ENG":"Tch. I knew it wouldn't work. How could I possibly know what's going on inside your head? After all, I'm not Jackson.","TWN":"嘖，還是沒辦法。我又不是傑森，怎麼可能摸清你那深不可測的心思。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"솔직하게 말해 봐. 결정에 불만이 없는 건 아니겠지?","JPN":"正直に言ってみろ。決定に不満がないわけではないだろう？","ENG":"Tell me the truth. You're not happy with my decision, are you?","TWN":"你老實說，你對於我們的決定是有怨言的吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"솔직히 섭섭하긴 하더군.","JPN":"まあ、寂しくはあったな。","ENG":"I was disheartened, to be honest.","TWN":"老實說是有點難過。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"이래서 자식 농사 소용 없다는 건가 싶었지.","JPN":"恩を仇で返すとはこのことか、と思った。","ENG":"All my efforts for the better future, gone to waste.","TWN":"所以說花這麼多心思栽培人有什麼用呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥……","JPN":"フン……","ENG":"Hmph...","TWN":"哼……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"감찰부가 움직이기 전까지는 아직 시간이 남아 있어.","JPN":"監察部が動くまではまだ時間がある。","ENG":"There's still time before the Inspection Corps looks into your case.","TWN":"在監察部行動前你還有時間。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"정말 오해를 풀고 싶다면, 합의한 시니어들을 설득하도록 해.","JPN":"本当に誤解を解きたいなら、合意したシニアを説得することだ。","ENG":"If there's any misunderstanding you want to set straight, you'd better start persuading the other Seniors.","TWN":"要想解開誤會，就說服其他的Senior吧。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"과반수를 넘어야 다시 안건으로 넘길 수 있을 테니까.","JPN":"過半数を越えれば、再度案件として戻せるからな。","ENG":"You'll need to convince half of them to put it back on the agenda.","TWN":"要過半數才能發回重審。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 자네부터 시작하면 되겠나?","JPN":"では、君から始めればいいのかい？","ENG":"Then I should probably start with you, no?","TWN":"那從你開始可以嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하. 철면피가 따로 없네….","JPN":"は。面の皮が厚いにもほどがある……","ENG":"Ugh, you and your thick skin...","TWN":"哈，真的是有夠厚臉皮的…"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"미리 말해 두는데, 내 결정을 철회하는 건 일찌감치 포기해.","JPN":"あらかじめ言っておくが、私の決定を撤回する作戦なら早々にあきらめることだ。","ENG":"Fair warning, it's best you give up trying to make me change my mind.","TWN":"醜話說前頭，我勸你打消念頭，我是不會收回決定的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"애초에 난 최고 관리자란 자리가 종신직으로 끝나선 안 된다고 생각하거든.","JPN":"そもそも私は、最高管理者という地位が終身雇用であってはならないと思っているからな。","ENG":"Personally, I've always thought the position of Supreme Administrator shouldn't be tenured.","TWN":"我從以前就認為，最高管理者的位置不能是終身職。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신의 실력으로 문제를 해결할 수 있다는 걸 증명해 보라고.","JPN":"あなたの実力で問題を解決できるということを証明して見せろ。","ENG":"Prove to me that you can resolve this on your own.","TWN":"請證明你有解決問題的能力。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 자리에 걸맞은 인물인지 말이야.","JPN":"その地位に相応しい人物かをな。","ENG":"Show me that you are fit to be in that position.","TWN":"證明你是有資格坐在那個位置的人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>탑승 안내말씀 드리겠습니다.</color>","JPN":"<color=#ffd34c>ご案内いたします。</color>","ENG":"<color=#ffd34c>Attention all boarding passengers.</color>","TWN":"<color=#ffd34c>登機通知。</color>"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샤레이드로 가는 플라티나 항공 PE501편이 잠시 후 탑승구에서 탑승을 시작합니다.</color>","JPN":"<color=#ffd34c>この後、シャレード行きのプラチナ空港PE501便の搭乗が搭乗口にて開始されます。</color>","ENG":"<color=#ffd34c>The boarding for Platina Airline Flight PE501 to Charade will commence shortly.</color>","TWN":"<color=#ffd34c>飛往查雷德的白金航空PE501號班機，稍後將開放登機。</color>"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>탑승 마감 시간은 출발 5분 전입니다.</color>","JPN":"<color=#ffd34c>搭乗締め切り時刻は出発時刻の5分前となります。</color>","ENG":"<color=#ffd34c>The final boarding will close 5 minutes before takeoff. Thank you.</color>","TWN":"<color=#ffd34c>起飛前5分鐘將停止登機服務。</color>"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠, 그럼 몇 밤 자면 오는 거야?","JPN":"パパ、じゃあ何日したら帰ってくるの？","ENG":"Daddy, how many nights do I have to sleep to see you again?","TWN":"爸爸，這次我要睡幾晚你才會回來呢？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마렴, 시그마. 백 밤 자면 돌아올 거란다.","JPN":"心配するな、シグマ。百日したら帰ってくるよ。","ENG":"Don't worry, Sigma. It'll only be a hundred nights.","TWN":"西格瑪別擔心，等你睡一百晚後爸爸就回來囉。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"백 밤이나~? 심심하겠다~","JPN":"百日も～？　つまんない～","ENG":"A hundred nights?! I'm gonna be so bored...!","TWN":"睡一百晚喔～？那我會很無聊欸～"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 모네랑 다른 아이들도 있으니 사이 좋게 지내렴.","JPN":"ハハ、モネや他の子たちもいるから、仲良くしなさい。","ENG":"Haha, you can play with Mone and the other children.","TWN":"哈哈，莫妮和其他小朋友都在，你們要好好相處喔。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"루시드 양 말도 잘 듣고. 알겠지?","JPN":"ルシード君の言うこともちゃんと聞くんだ。わかったかい？","ENG":"And listen to Lucid, okay?","TWN":"要聽露西德姊姊的話喔，知道嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗! 사장님, 어서오세요!","JPN":"あっ！　社長、こんにちは！","ENG":"Oh! Boss, welcome!","TWN":"喔！老闆你好！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"시그마랑 전화했어? 진짜 아빠라고 해도 믿겠네.","JPN":"シグマと電話してたの？　本当のパパみたいだね。","ENG":"Did you talk with Sigma on the phone? People might really think you're her father or something.","TWN":"老闆和西格瑪通過電話了嗎？說老闆是親生爸爸我也信呢。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"생물학적으로는 아니어도 부녀 관계는 맞지.","JPN":"生物学的には違っても、親子関係ではあるからね。","ENG":"We might not be biologically related, but she is still my daughter.","TWN":"雖然在生物學上不是，但我們確實是父女。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 그 쇼핑백들은 다 뭔가?","JPN":"ところで、その紙袋はいったい何だい？","ENG":"But what's with all the shopping bags?","TWN":"不過那些購物袋是怎麼回事？"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"난 모르는 일이야. 얘가 전부 사 버렸어.","JPN":"知らない。全部この子が買った物だよ。","ENG":"I dunno. She bought them all.","TWN":"不關我的事，全是她買的。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"힐데 소대장님이랑 주시윤님을 만나면 드릴 선물이에요!","JPN":"ヒルデ小隊長様とシリュウ様にお会いしたらお渡しするプレゼントなんです！","ENG":"They're presents for Commander Hilde and Mr. Joo Shiyoon when I meet them!","TWN":"這是我要送給希爾德小隊長和周時雲先生的禮物！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그리고 다른 직원 분들 것도요. 샤레이드 지부에서 일하는 분들에게도 인사 드려야죠.","JPN":"それに他の社員の方の分も。シャレード支部で働く方にもご挨拶しないと。","ENG":"There's also some for others too. I should also say hello to the workers at the Charade branch.","TWN":"其他員工的禮物我也有準備，還有在查雷德分公司的大家也有喔。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"낯 간지러우니까 님 자 좀 그만 붙여.","JPN":"恥ずかしいから、様はやめて。","ENG":"Could you please drop the honorifics? It gives me goosebumps whenever you say it.","TWN":"聽起來怪噁心的，把先生、小姐拿掉，直接叫名字就好。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?! 그, 그그그럼 제가 유미나님을 감히 선배라고 불러도 되나요?!","JPN":"はい！？　そ、そそそれじゃあ、私がミナ様を先輩って呼んじゃってもいいんですか！？","ENG":"Huh?! Th-th-then...! Can I just call you Mina?!","TWN":"什麼？！所，所，所，所以我可以叫劉米娜小姐前輩嗎？！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"마음껏 불러. 차라리 그 편이 나도 편하니까.","JPN":"好きにして。いっそその方が私も気が楽だから。","ENG":"Sure, go for it. It's better for me too.","TWN":"就叫吧，總比叫小姐好。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 미나 선배! 미나 선배! 미나 선배! 미나미나미나 선배!","JPN":"ミナ先輩！　ミナ先輩！　ミナ先輩！　ミナ先輩！　ミナミナミナ先輩！","ENG":"Mina! Mina! Mina! Mina! Mina, Mina, Mina!","TWN":"米娜前輩！米娜前輩！米娜前輩！米娜前輩！米娜米娜米娜前輩！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 지부 사람들이 잘들 일하고 있는지 궁금해지는군.","JPN":"ハハ、支部のみんながちゃんと働いているか、気になるな。","ENG":"Haha, I'm curious to see if my employees over at Charade are doing a good job.","TWN":"哈哈，不知道分公司的人有在認真上班嗎？"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……부사장이 조세 회피 목적으로 세운 곳이라고 들었거든.","JPN":"……副社長が租税回避のために作ったところだと聞いたが。","ENG":"I heard the Vice President created that branch just for tax evasion purposes.","TWN":"……聽說副總設立那間分公司是因為要避稅。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아……. 그냥 고생길이 활짝 열렸다고 하지.","JPN":"はあ……これからの苦労が目に見えるよ。","ENG":"*Sigh...* Just tell us that we're screwed, why don't you?","TWN":"哀……我看苦日子要來囉。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조금만 참게나. 시니어들과 교섭해서 결정을 되돌리려는 거니까.","JPN":"少しだけ耐えてくれ。シニアと交渉して決定を覆そうとしているところだから。","ENG":"Just be patient for a while. I'll do my best to change the Seniors' minds.","TWN":"忍耐一下，這是和Senior交涉收回決定的手段。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 샤레이드가 좋겠지. 현지 정황을 잘 아는 태스크포스도 있고.","JPN":"それにはシャレードがちょうどいい。現地の状況に詳しいタスクフォースもある。","ENG":"Maybe Charade is good to start. I know a TASKFORCE that's familiar with the area.","TWN":"查雷德很不錯吧？而且還有清楚當地情況的特遣勢力在。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐, 우린 호위로 따라가는 거니까. 응원은 할게.","JPN":"ま、私たちは護衛だから。応援はするよ。","ENG":"Well, we're just following as escorts. I wish you a good luck.","TWN":"反正我們是保鑣的角色，你加油。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 의외로군. 왜 갑자기 채용하기로 마음을 먹었나?","JPN":"それにしても意外だったな。どうしていきなり採用することにしたんだい？","ENG":"It's still surprising to me. What made you reconsider hiring a new recruit, Mina?","TWN":"不過我有點意外，米娜怎麼會突然決定要錄用她呢？"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……요리를 할 줄 안다잖아. 컵라면만 먹기 싫었을 뿐이야.","JPN":"……料理ができるんだって。カップラーメンばかり食べたくなかっただけだよ。","ENG":"...She says she knows how to cook. I just want to stop having cup noodles for every meal.","TWN":"……她不是說專長是做菜嗎？我只是不想餐餐吃泡麵而已。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 그렇군. 식사도 중요한 문제이긴 하지.","JPN":"ふむ。そうか。食事も重要な問題ではあるな。","ENG":"Hmm, I see. A good diet is important.","TWN":"嗯哼，原來是這樣，吃飯確實是很重要的問題沒錯。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가뜩이나 르네 양이 자산까지 동결시켰으니 말이야.","JPN":"ルネ君が資産まで凍結してしまったからな。","ENG":"Especially since Renée froze all of our accounts.","TWN":"加上芮妮還把公司的財產凍結起來。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마세요! 미나 선배! 사장님!","JPN":"心配しないでください！　ミナ先輩！　社長！","ENG":"Don't worry, Mina! Boss!","TWN":"米娜前輩！老闆！大家請放心！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제가 만든 요리를 한 번 맛보면 헤어나올 수 없을 테니까요! 기대해 주세요!","JPN":"一度私の料理を味えば、ハマっちゃうこと間違いなしですから！　お楽しみに！","ENG":"Once you get a taste of my cooking, you'll never want anything else! Just you wait!","TWN":"我做的菜你們吃過一次就會上癮的！敬請期待吧！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그거 기대가 되는군.","JPN":"ハハ、それは楽しみだな。","ENG":"Ha ha, sounds wonderful.","TWN":"哈哈，真是令人期待呢。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"...Phew.","TWN":"……呼。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"슬슬 탑승할 시간이야. 움직이자.","JPN":"そろそろ搭乗する時間だ。行こう。","ENG":"C'mon, let's go. It's almost boarding time.","TWN":"差不多到登機時間了，走吧。"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 기대되네요! 저 비행기는 처음 타 보거든요!","JPN":"はい！　楽しみですね！　私、飛行機は初めてなんです！","ENG":"Okay! I'm so excited! It's my first time getting on an airplane!","TWN":"是！好期待喔！我是第一次搭飛機欸！"},"stage":{"bg":"SP_001","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};